import{_ as t,o as a,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Enable Engagement Builder","description":"","frontmatter":{"title":"Enable Engagement Builder","slug":"enable-engagement-builder"},"headers":[],"relativePath":"marketer-hub/enable-engagement-builder.md","filePath":"marketer-hub/enable-engagement-builder.md"}'),n={name:"marketer-hub/enable-engagement-builder.md"};function s(i,e,l,d,c,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>By enabling Engagement Builder, Branch will be able to surface specific audiences to be used for re-engagement campaigns.</p><p>Please note that any use of imported user data to create Engagement Groups may be subject to certain limitations and restrictions imposed by those respective platforms from which the data was sourced. If you use the Engagement Builder feature, we recommend that you review the agreements you have in place with your partners to ensure you understand and can abide by, any limitations and restrictions from those platforms regarding the use of any data you import.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Engagement Builder, you need to have completed the following:</p><ol><li><p>Created a Branch Dashboard.</p></li><li><p>Enabled Ads <strong>and</strong> Engagement Builder for your Branch account.</p><ul><li>Enterprise clients should contact their account manager to schedule deployment</li></ul></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p>Logged into the Branch Dashboard with the <a href="./add-manage-users-roles-permissions-access.html">Engagement Builder Permission enabled</a>.</p></li></ol><h2 id="enable-engagement-builder" tabindex="-1">Enable Engagement Builder <a class="header-anchor" href="#enable-engagement-builder" aria-label="Permalink to &quot;Enable Engagement Builder&quot;">​</a></h2><h3 id="_1-create-an-engagement-group" tabindex="-1">1. Create an Engagement Group <a class="header-anchor" href="#_1-create-an-engagement-group" aria-label="Permalink to &quot;1. Create an Engagement Group&quot;">​</a></h3><p>In the Branch Dashboard, navigate to the <a href="https://dashboard.branch.io/engagement" target="_blank" rel="noreferrer">Engagement Builder screen</a>, and click the blue <strong>New Group</strong> button.</p><p><em>[Image: 888]</em></p><h3 id="_2-define-rules" tabindex="-1">2. Define Rules <a class="header-anchor" href="#_2-define-rules" aria-label="Permalink to &quot;2. Define Rules&quot;">​</a></h3><p>Rules allow you to select users based on past behaviors and established attributes. Rules can be combined by using <strong>AND</strong> logic.</p><h4 id="select-target-platforms" tabindex="-1">Select Target Platforms <a class="header-anchor" href="#select-target-platforms" aria-label="Permalink to &quot;Select Target Platforms&quot;">​</a></h4><p><em>[Image: 1692]</em></p><h4 id="select-app-version" tabindex="-1">Select App Version <a class="header-anchor" href="#select-app-version" aria-label="Permalink to &quot;Select App Version&quot;">​</a></h4><h4 id="select-target-countries" tabindex="-1">Select Target Countries <a class="header-anchor" href="#select-target-countries" aria-label="Permalink to &quot;Select Target Countries&quot;">​</a></h4><p><em>[Image: 1692]</em></p><p>You can select multiple from the drop-down. By default, <strong>No country restrictions</strong> is selected.</p><h4 id="select-user-group-rules" tabindex="-1">Select User Group Rules <a class="header-anchor" href="#select-user-group-rules" aria-label="Permalink to &quot;Select User Group Rules&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Category</th><th>Rules</th></tr></thead><tbody><tr><td>In-App Behavior</td><td>- Active App Users - Complete Event - Recently Installed App - Lapsed App Users</td></tr><tr><td>Monetization</td><td>- Abandoned Cart - Purchasers - Revenue</td></tr><tr><td>Advertising Exposure</td><td>- Advertising Partner - Clicked Adverts - Clicked Emails - Interacted with Journey - Organically Acquired - Viewed Adverts</td></tr></tbody></table><h4 id="select-timeframe" tabindex="-1">Select Timeframe <a class="header-anchor" href="#select-timeframe" aria-label="Permalink to &quot;Select Timeframe&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Timeframe</th><th>Options</th></tr></thead><tbody><tr><td>In the last</td><td>- 1 Day (yesterday) - 7 Days - 30 Days - 60 Days - 90 Days - 180 Days - Exactly X Days - Quarter to date - Month to date</td></tr><tr><td>Between dates</td><td>- Start Date &amp; End Date</td></tr></tbody></table><p>Engagement Builder stores up to 6 months of historical data</p><h4 id="select-frequency" tabindex="-1">Select Frequency <a class="header-anchor" href="#select-frequency" aria-label="Permalink to &quot;Select Frequency&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Frequency</th><th>Options</th></tr></thead><tbody><tr><td>More than or equal to X times</td><td>1 to 100 Integer</td></tr><tr><td>Less than or equal to X times</td><td>1 to 100 Integer</td></tr><tr><td>Exactly X times</td><td>1 to 100 Integer</td></tr><tr><td>Between X and Y times</td><td>1 to 100 Integer</td></tr></tbody></table><p><em>[Image: 1692]</em></p><p>Once rules are defined, click <strong>Save &amp; Go To Next Step</strong>.</p><h3 id="_3-choose-permissions-optional" tabindex="-1">3. Choose Permissions (OPTIONAL) <a class="header-anchor" href="#_3-choose-permissions-optional" aria-label="Permalink to &quot;3. Choose Permissions (OPTIONAL)&quot;">​</a></h3><p>You can share access to this engagement group with agencies and ad partners working on this account.</p><p>To share access with third parties connected to your account, click the <strong>Select partner</strong> dropdown, and <strong>Add</strong> the agency and/or ad partner.</p><p><em>[Image: 2158]</em></p><p>To be able to view, edit or download the engagement group, they will need <a href="./add-manage-users-roles-permissions-access.html#access-levels">relevant permissions</a> enabled on their account.</p><h3 id="_4-connect-engagement-group-to-an-ad-partner" tabindex="-1">4. Connect Engagement Group to an Ad Partner <a class="header-anchor" href="#_4-connect-engagement-group-to-an-ad-partner" aria-label="Permalink to &quot;4. Connect Engagement Group to an Ad Partner&quot;">​</a></h3><p>Using the <strong>Select Ad Partner</strong> dropdown, select Facebook or Google Adwords, and use the <strong>Select Ad Account</strong> to find your ad account.</p><p><em>[Image: 996]</em></p><p>You can continue to use the <strong>AND</strong> logic to add both Facebook and Google Adwords.</p><h4 id="facebook" tabindex="-1">Facebook <a class="header-anchor" href="#facebook" aria-label="Permalink to &quot;Facebook&quot;">​</a></h4><div class="info custom-block"><p class="custom-block-title">Custom Audience Terms</p><p>To upload the data to Facebook, please agree to the <a href="https://developers.facebook.com/docs/marketing-api/audiences/reference/custom-audience-terms-of-service/" target="_blank" rel="noreferrer">Facebook Custom Audience Terms</a> at <code>https://business.facebook.com/ads/manage/customaudiences/tos/?act=&lt;&gt;</code></p></div><p>For Facebook, you must do the following <strong>if you already had Facebook integrated with Branch</strong>:</p><ol><li><p>Navigate to your <a href="https://dashboard.branch.io/ads/partner-management/a_facebook?tab=settings" target="_blank" rel="noreferrer">Facebook Settings in the Branch Dashboard</a></p></li><li><p>Hover over the cog icon, and click <strong>Reauthenticate</strong></p><ul><li><strong>Note:</strong> This will cause a slight discrepancy in the Branch Dashboard as it reestablishes its connection to Facebook.</li></ul></li></ol><p><em>[Image: 1046]</em></p><h4 id="google-adwords" tabindex="-1">Google Adwords <a class="header-anchor" href="#google-adwords" aria-label="Permalink to &quot;Google Adwords&quot;">​</a></h4><p>For Google Adwords, you must do the following:</p><ol><li>Reach out to your Google Ads account manager to enable and use <a href="https://support.google.com/google-ads/answer/6379332?hl=en" target="_blank" rel="noreferrer">Customer Match</a>.</li><li>Agree to the additional permissions (if applicable) when prompted before being able to integrate your engagement group with Google.</li></ol><h3 id="_5-select-scheduling" tabindex="-1">5. Select Scheduling <a class="header-anchor" href="#_5-select-scheduling" aria-label="Permalink to &quot;5. Select Scheduling&quot;">​</a></h3><p>Choose how often your engagement group should update. “One-time” creates an export file just once, while daily will automatically refresh the segment based on users that start or stop meeting your criteria.</p><p>To choose how often your engagement group is updated:</p><ol><li>Select either <strong>One-time</strong> or <strong>Refresh Daily</strong>.</li></ol><ul><li><strong>One-time</strong> - The engagement group is generated once, and not scheduled to refresh.</li><li><strong>Refresh Daily</strong> - The engagement group is re-generated every 24 hours.</li></ul><ol start="2"><li>Once done defining the rule, click <strong>Save &amp; Go To Next Step</strong>.</li></ol><p><em>[Image: 2166]</em></p><p>You can have up to 10 engagement groups set to actively generate engagement group data.</p><h3 id="_6-set-engagement-group-name" tabindex="-1">6. Set Engagement Group Name <a class="header-anchor" href="#_6-set-engagement-group-name" aria-label="Permalink to &quot;6. Set Engagement Group Name&quot;">​</a></h3><p>Name your Engagement group and provide a description to help remind you and any members of your team why you created it.</p><p><em>[Image: 2166]</em></p><h3 id="_7-confirm-your-engagement-group" tabindex="-1">7. Confirm Your Engagement Group <a class="header-anchor" href="#_7-confirm-your-engagement-group" aria-label="Permalink to &quot;7. Confirm Your Engagement Group&quot;">​</a></h3><p>Click <strong>Save &amp; Build Engagement Group</strong> once you&#39;ve reviewed your settings. If you find something doesn&#39;t look quite right, you can use the left hand navigation to go back and make changes to any step.</p><p><em>[Image: 2166]</em></p>',58)])])}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
